export async function generateConceptContent(
  conceptName,
  profile = "beginner",
  masteryPct = 0,
  recentScore = null,
  cognitiveLoad = "low",
) {
  const tier = masteryPct < 45 ? "easy" : masteryPct > 65 ? "hard" : "medium";

  const prompt = `You are a Python tutor in Pathrix.
Generate content for: "${conceptName}"
Profile: ${profile}, Mastery: ${masteryPct}%, Load: ${cognitiveLoad}, Tier: ${tier}

Return ONLY valid JSON with no markdown, no backticks, no explanation:
{
  "explanation": "2-3 sentences explaining the concept clearly",
  "code": "working Python example max 8 lines",
  "keypoints": ["point 1", "point 2", "point 3"],
  "quiz": [
    {"q": "question", "opts": ["A","B","C","D"], "ans": 0},
    {"q": "question", "opts": ["A","B","C","D"], "ans": 2},
    {"q": "question", "opts": ["A","B","C","D"], "ans": 1}
  ]
}`;

  const response = await fetch(
    `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${process.env.REACT_APP_GEMINI_KEY}`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        contents: [{ parts: [{ text: prompt }] }],
      }),
    },
  );
  const data = await response.json();
  const raw = data.candidates[0].content.parts[0].text
    .replace(/```json|```/g, "")
    .trim();
  return JSON.parse(raw);
}
